/**
 * Gentelella Admin Template - Custom JS
 * Sidebar toggle, menu active state, NProgress init
 */
$(document).ready(function() {
    // Sidebar toggle
    $('#menu_toggle').on('click', function() {
        var body = $('body');
        if (body.hasClass('nav-md')) {
            body.removeClass('nav-md').addClass('nav-sm');
            $('.left_col').css('width', '70px');
            $('.right_col, footer').css('margin-left', '70px');
            $('.nav_title span, .menu_section h3, .profile_info, .nav.side-menu > li > a span').hide();
        } else {
            body.removeClass('nav-sm').addClass('nav-md');
            $('.left_col').css('width', '230px');
            $('.right_col, footer').css('margin-left', '230px');
            $('.nav_title span, .menu_section h3, .profile_info, .nav.side-menu > li > a span').show();
        }
    });

    // Add span wrapper to menu text for toggle
    $('.nav.side-menu > li > a').each(function() {
        var $this = $(this);
        var html = $this.html();
        // Don't re-wrap if already wrapped
        if (html.indexOf('<span') === -1) {
            var parts = html.split('</i>');
            if (parts.length > 1) {
                $this.html(parts[0] + '</i><span>' + parts[1] + '</span>');
            }
        }
    });

    // NProgress complete on page loaded
    if (typeof NProgress !== 'undefined') {
        NProgress.done();
    }

    // Dropdown toggle for top nav
    $(document).on('click', '.dropdown-toggle', function(e) {
        e.preventDefault();
        var $parent = $(this).parent();
        $parent.toggleClass('open');
    });

    // Close dropdowns when clicking elsewhere
    $(document).on('click', function(e) {
        if (!$(e.target).closest('.dropdown').length) {
            $('.dropdown').removeClass('open');
        }
    });
});
